import { generateObject, zodSchema } from 'ai';
import { z } from 'zod';
import { vexMiddleware } from '@vex_dev/sdk';

const DecisionRecord = z.object({
  decision: z.enum(['approved', 'denied']),
  reasoning: z.string().min(50),
  confidence: z.number().min(0.7),
  appealInstructions: z.string()
});

const vex = vexMiddleware({
  projectId: 'gov-vercel-ai',
  schemaValidation: true,
  minConfidence: 0.75
});

export async function generateDecision(query: string) {
  const result = await generateObject({
    model: openai('gpt-4o'),
    schema: DecisionRecord,
    prompt: `Government decision for: ${query}`,
    ...vex({
      providerFallback: 'anthropic/claude-3-5-sonnet-20240620'
    })
  });
  return result.object;
}
